uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;

//vUv mit Wasseroberflaeche modulieren
dz1.x = GetBuf(vUv+pix*vec2(1,0)) - GetBuf(vUv+pix*vec2(-1,0));
dz1.y = GetBuf(vUv+pix*vec2(0,1)) - GetBuf(vUv+pix*vec2(0,-1));
vUv += dz1 * clamp01(1-GetBuf(uv0))*.4;

vec3 shine = 0; radi = 1;
for (int n=1; n <= anz;  n++)
{
  vec2 uv2= (vUv-moonpos)*radi+moonpos;
  shine.b= max(shine.b, GetBlur1(uv2).b*(1-1.0*n/anz));
  radi += .5/anz;
}

//Untergrund
vec3 bk= texture(sampler_smalltiled_lizard_scales,vUv +dz1)  *0.5;
ret = bk;

ret -= shine.b*0.75;
ret = sat(ret+ 1.3*GetPixel(vUv).b);

//float glow =  GetBlur3(vUv).b* texture3D(sampler_noisevol_hq,vec3(vUv/2,uTime/8)).r*q10;
//ret+=glow*vec3(1,0.7,2)*.3;

uv3=(vUv-0.5)*uAspect.xy;
uv2=uv3-vec2(q1,-q2);
li = 0.03/pow(length(uv2),1);
ret+= li*(.4+bk)*audioHighSmooth;

uv2.x=uv3.x-mix(q1,-q1,q5);
uv2.y=uv3.y-mix(-q2,q2,q6);
li = 0.03/pow(length(uv2),1);
ret+= li*(.4+bk)*audioHighSmooth*(q7>0.3);

//ret = GetPixel(vUv);

  fragColor = ret;
}
